import uasyncio as asyncio
import ujson as json
from machine import Pin
from websockets import serve

# Define the pin for the IoT device
device_pin = Pin(2, Pin.OUT)

async def handle_client(websocket, path):
    async for message in websocket:
        try:
            data = json.loads(message)
            if 'action' in data:
                if data['action'] == 'turn_on':
                    device_pin.on()
                    await websocket.send(json.dumps({"status": "Device turned on"}))
                elif data['action'] == 'turn_off':
                    device_pin.off()
                    await websocket.send(json.dumps({"status": "Device turned off"}))
                else:
                    await websocket.send(json.dumps({"error": "Unknown action"}))
            else:
                await websocket.send(json.dumps({"error": "Invalid command"}))
        except Exception as e:
            await websocket.send(json.dumps({"error": str(e)}))

async def main():
    async with serve(handle_client, "0.0.0.0", 8765):
        await asyncio.Future()  # Run forever

try:
    asyncio.run(main())
except KeyboardInterrupt:
    print("Server stopped")